sql:
SELECT COUNT(visit_id) AS NumberOfVisits
FROM visits
WHERE trial_id = 'YourSpecificTrialId';

SELECT u.username
FROM users u
WHERE u.role = 'researcher' AND u.access_level = 'level_1';

SELECT name, contact_info
FROM patients
WHERE usubjid = '0';

SELECT v.usubjid, a.paramcd, v.visit_date
FROM visits v
INNER JOIN assessments a ON v.usubjid = a.usubjid AND v.visit_type = 'VISIT 1' AND a.avisit = 'VISIT 1';

SELECT visit_id, usubjid, visit_date
FROM visits
WHERE trial_id = 1 AND visit_date = '2022-02-15';

SELECT param_description 
FROM parameters 
WHERE paramcd = '1';
